	//  4: 逆 - 后到i    v[n]+v[n-1]+...+v[i] - (c-x[i])



	//  1: 逆 - 后到 i~n 的最大值

	//  2: 逆 - 先到 i~n 的最大值

	//  3: 顺 - 后到 1~i 的最大值

	//  4: 顺 - 先到 1~i 的最大值

	for(register int i=n;i>=1;i--)

	{

		ma[1][i]=max(ma[1][i+1],k[4][i]);

