		ans=max(sum,ans);

		sum=k[4][i]+ma[4][i-1];//后逆到 i 先顺到 j  (i>j)

		ans=max(sum,ans);

	}

	if(ans<0LL)  puts("0");

	else  printf("%lld",ans);

	return 0;

}

